// CF14 WF_STYLE_DNA — normalize payload, resolve channel_url -> channel_id,
// idempotency check against style_profiles (within last 30 days).
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || raw;

const channelUrl = payload.channel_url || '';
const channelIdInput = payload.channel_id || '';
const projectId = payload.project_id || null;
const applyToProject = payload.apply_to_project === true;
const force = payload.force === true;

if (!channelUrl && !channelIdInput) {
  return [{
    json: {
      success: false,
      error: 'Provide { channel_url } or { channel_id }',
      http_status: 400,
      via_webhook: viaWebhook
    }
  }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const ytKey = $env.YOUTUBE_API_KEY;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), attempts: attempt };
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

// Resolve channel_id from URL
let channelId = channelIdInput;
let channelHandle = null;

if (!channelId && channelUrl) {
  // Direct /channel/UC... URL
  const ucMatch = channelUrl.match(/youtube\.com\/channel\/(UC[A-Za-z0-9_-]{22})/i);
  if (ucMatch) {
    channelId = ucMatch[1];
  } else {
    // @handle URL
    const handleMatch = channelUrl.match(/youtube\.com\/@([A-Za-z0-9._-]+)/i);
    if (handleMatch) {
      channelHandle = handleMatch[1];
      // forHandle requires @ prefix
      const byHandleUrl = `https://www.googleapis.com/youtube/v3/channels?part=id&forHandle=@${channelHandle}&key=${ytKey}`;
      const byHandleRes = await fetchWithRetry(byHandleUrl, { method: 'GET' }, 'yt_channels_by_handle');
      if (byHandleRes.ok && byHandleRes.json?.items?.length > 0) {
        channelId = byHandleRes.json.items[0].id;
      } else {
        // Fallback: search
        const sUrl = `https://www.googleapis.com/youtube/v3/search?part=snippet&type=channel&q=${encodeURIComponent(channelHandle)}&maxResults=1&key=${ytKey}`;
        const sRes = await fetchWithRetry(sUrl, { method: 'GET' }, 'yt_search_channel');
        if (sRes.ok && sRes.json?.items?.length > 0) {
          channelId = sRes.json.items[0].snippet?.channelId || sRes.json.items[0].id?.channelId;
        }
      }
    } else {
      // Legacy /user/ URL or /c/ URL — search by path segment
      const pathMatch = channelUrl.match(/youtube\.com\/(?:user|c)\/([A-Za-z0-9._-]+)/i);
      if (pathMatch) {
        const q = pathMatch[1];
        const sUrl = `https://www.googleapis.com/youtube/v3/search?part=snippet&type=channel&q=${encodeURIComponent(q)}&maxResults=1&key=${ytKey}`;
        const sRes = await fetchWithRetry(sUrl, { method: 'GET' }, 'yt_search_channel');
        if (sRes.ok && sRes.json?.items?.length > 0) {
          channelId = sRes.json.items[0].snippet?.channelId || sRes.json.items[0].id?.channelId;
        }
      }
    }
  }
}

if (!channelId) {
  return [{
    json: {
      success: false,
      error: `Could not resolve channel from input (channel_url=${channelUrl}, channel_id=${channelIdInput})`,
      http_status: 400,
      via_webhook: viaWebhook
    }
  }];
}

// Idempotency: existing row within last 30 days for (project_id, channel_id)?
if (!force) {
  const thirtyDaysAgo = new Date(Date.now() - 30 * 86400000).toISOString();
  let idemUrl = `${supabaseUrl}/rest/v1/style_profiles?channel_id=eq.${encodeURIComponent(channelId)}&analyzed_at=gte.${encodeURIComponent(thirtyDaysAgo)}&order=analyzed_at.desc&limit=1&select=*`;
  if (projectId) {
    idemUrl += `&project_id=eq.${projectId}`;
  } else {
    idemUrl += `&project_id=is.null`;
  }
  const idemRes = await fetch(idemUrl, { method: 'GET', headers: sbHeaders });
  if (idemRes.ok) {
    const arr = await idemRes.json();
    if (Array.isArray(arr) && arr.length > 0) {
      return [{
        json: {
          success: true,
          skipped: true,
          reason: 'Existing style_profile within last 30 days (pass force=true to rerun)',
          style_profile: arr[0],
          http_status: 200,
          via_webhook: viaWebhook
        }
      }];
    }
  }
}

return [{
  json: {
    channel_id: channelId,
    channel_url: channelUrl || `https://www.youtube.com/channel/${channelId}`,
    channel_handle: channelHandle,
    project_id: projectId,
    apply_to_project: applyToProject,
    force,
    via_webhook: viaWebhook,
    triggered_at: new Date().toISOString()
  }
}];

// Fetch channel metadata + 20 most recent uploads with stats + thumbnails.
// Uses inline backoff. Quota exhaustion -> surface error back to caller.

const data = $input.first().json;
if (data.success === false || data.skipped) return $input.item;

const channelId = data.channel_id;
const ytKey = $env.YOUTUBE_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (res.ok) return { ok: true, json: await res.json(), attempts: attempt };
      const body = await res.text();
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

function parseIsoDuration(s) {
  if (!s || typeof s !== 'string') return 0;
  const m = s.match(/^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/);
  if (!m) return 0;
  return parseInt(m[1]||'0',10)*3600 + parseInt(m[2]||'0',10)*60 + parseInt(m[3]||'0',10);
}

// 1. channels.list
const chInfoUrl = `https://www.googleapis.com/youtube/v3/channels?part=snippet,statistics,contentDetails&id=${channelId}&key=${ytKey}`;
const chInfo = await fetchWithRetry(chInfoUrl, { method: 'GET' }, 'yt_channels');
if (chInfo.quota) {
  return [{ json: { success: false, error: 'YouTube quota exhausted', http_status: 429, via_webhook: data.via_webhook } }];
}
if (!chInfo.ok || !(chInfo.json?.items?.length)) {
  return [{ json: { success: false, error: `Channel fetch failed: ${chInfo.error || 'empty result'}`, http_status: 500, via_webhook: data.via_webhook } }];
}

const chItem = chInfo.json.items[0];
const channelName = chItem.snippet?.title || '';
const uploadsPlaylistId = chItem.contentDetails?.relatedPlaylists?.uploads;
const subCount = parseInt(chItem.statistics?.subscriberCount || '0', 10);

if (!uploadsPlaylistId) {
  return [{ json: { success: false, error: 'Channel has no uploads playlist', http_status: 500, via_webhook: data.via_webhook } }];
}

// 2. playlistItems.list -> 20 most recent
const plUrl = `https://www.googleapis.com/youtube/v3/playlistItems?part=snippet,contentDetails&playlistId=${uploadsPlaylistId}&maxResults=20&key=${ytKey}`;
const plRes = await fetchWithRetry(plUrl, { method: 'GET' }, 'yt_playlistItems');
if (plRes.quota) return [{ json: { success: false, error: 'YouTube quota exhausted', http_status: 429, via_webhook: data.via_webhook } }];
if (!plRes.ok) return [{ json: { success: false, error: `playlistItems failed: ${plRes.error}`, http_status: 500, via_webhook: data.via_webhook } }];

const videoIds = (plRes.json?.items || []).map(it => it.contentDetails?.videoId || it.snippet?.resourceId?.videoId).filter(Boolean);

if (videoIds.length === 0) {
  return [{ json: { success: false, error: 'No uploads found', http_status: 500, via_webhook: data.via_webhook } }];
}

// 3. videos.list batched (max 50 per call; 20 is fine in one call)
const vUrl = `https://www.googleapis.com/youtube/v3/videos?part=snippet,statistics,contentDetails&id=${videoIds.join(',')}&key=${ytKey}`;
const vRes = await fetchWithRetry(vUrl, { method: 'GET' }, 'yt_videos');
if (vRes.quota) return [{ json: { success: false, error: 'YouTube quota exhausted', http_status: 429, via_webhook: data.via_webhook } }];
if (!vRes.ok) return [{ json: { success: false, error: `videos.list failed: ${vRes.error}`, http_status: 500, via_webhook: data.via_webhook } }];

const videoItems = vRes.json?.items || [];
const now = Date.now();

const recentVideos = videoItems.map(v => {
  const pub = v.snippet?.publishedAt;
  const pubMs = pub ? new Date(pub).getTime() : now;
  const durationSec = parseIsoDuration(v.contentDetails?.duration);
  return {
    video_id: v.id,
    title: v.snippet?.title || '',
    views: parseInt(v.statistics?.viewCount || '0', 10),
    published_at: pub,
    days_ago: Math.max(0, Math.round((now - pubMs) / 86400000)),
    duration_seconds: durationSec,
    duration_minutes: Math.round((durationSec / 60) * 10) / 10,
    thumbnail_url: v.snippet?.thumbnails?.maxres?.url || v.snippet?.thumbnails?.high?.url || v.snippet?.thumbnails?.medium?.url || null
  };
}).sort((a, b) => (new Date(b.published_at).getTime() || 0) - (new Date(a.published_at).getTime() || 0));

// Cap thumbnails at 8 for Pass 2 (Vision cost + token budget)
const thumbnails = recentVideos.map(v => v.thumbnail_url).filter(Boolean).slice(0, 8);

return [{
  json: {
    ...data,
    channel_id: channelId,
    channel_name: channelName,
    channel_url: data.channel_url,
    channel_handle: data.channel_handle,
    subscriber_count: subCount,
    uploads_playlist_id: uploadsPlaylistId,
    recent_videos: recentVideos,
    thumbnail_urls: thumbnails,
    videos_count: recentVideos.length,
    thumbnails_count: thumbnails.length
  }
}];

// Pass 1: Title Analysis (Opus 4.6, text)
// Pass 2: Thumbnail DNA (Opus 4.6, Vision, up to 8 thumbnails)
// Pass 3: Content Strategy (Opus 4.6, text)
// Then: synthesize final style_profile record.
// Inline exponential backoff per pass. Partial analysis allowed — passes are independent.

const data = $input.first().json;
if (data.success === false || data.skipped) return $input.item;

const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const analysisStart = Date.now();

const recentVideos = data.recent_videos || [];
const thumbs = data.thumbnail_urls || [];
const channelName = data.channel_name || '';

async function callClaude(messages, maxTokens, maxRetries = 4, label = 'claude') {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-opus-4-6',
          max_tokens: maxTokens,
          messages
        })
      });
      if (res.ok) {
        const body = await res.json();
        return { ok: true, text: body.content?.[0]?.text || '', attempts: attempt };
      }
      const errBody = await res.text();
      // Vision rate limit: extra backoff
      if (res.status === 429) {
        await sleep(30000);
      }
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

function parseJson(text) {
  if (!text) return null;
  const clean = text.replace(/```json|```/g, '').trim();
  try { return JSON.parse(clean); } catch {}
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch {} }
  return null;
}

// ─── Pass 1: Title Analysis ───────────────────────────────────────────────
const titleLines = recentVideos.map((v, idx) => `${idx + 1}. "${v.title}" | Views: ${v.views} | Published: ${v.days_ago}d ago`).join('\n');
const pass1Prompt = `TITLE PATTERN ANALYSIS

Channel: ${channelName}
Last ${recentVideos.length} Video Titles (ordered newest → oldest):
${titleLines}

Analyze these titles and extract the dominant structural formulas this channel uses.

Look for:
1. Opening word patterns (Why / How / [Number] / I / The / etc.)
2. Length patterns (average chars, range)
3. Structural templates that recur (identify 3-5)
4. Emotional triggers used (fear / curiosity / desire / social proof)
5. Whether high-view titles differ structurally from low-view titles

Return ONLY this JSON:
{
  "title_formulas": [
    {
      "pattern_name": "<descriptive name for this formula>",
      "template": "<structural template with placeholders>",
      "example": "<one of their actual titles that fits>",
      "frequency_pct": <float 0-100>,
      "avg_views_when_used": <integer>,
      "emotional_trigger": "<fear|curiosity|desire|social_proof|mixed>"
    }
  ],
  "title_stats": {
    "avg_char_count": <integer>,
    "uses_numbers_pct": <float>,
    "starts_with_question_pct": <float>,
    "uses_parentheses_pct": <float>
  },
  "top_performing_formula": <index into title_formulas>,
  "title_pattern_summary": "<2-3 sentence description of their overall title strategy>"
}`;

const pass1 = await callClaude([{ role: 'user', content: pass1Prompt }], 1500, 4, 'pass1_titles');
const titleDNA = pass1.ok ? parseJson(pass1.text) : null;

// ─── Pass 2: Thumbnail DNA (Vision) ───────────────────────────────────────
const pass2TextPrompt = `THUMBNAIL DNA ANALYSIS

I'm showing you the thumbnails for ${channelName}'s recent videos. Analyze all of them together to identify consistent visual patterns.

For the entire set, identify:
1. Dominant color palette (top 3 colors in hex)
2. Text positioning (where does text typically appear: left / center / right / bottom / top / none)
3. Face presence (what % of thumbnails show a human face?)
4. Dominant emotional expression in face thumbnails
5. Background type (solid color / gradient / busy scene / blurred / stock photo)
6. Text characteristics (font style: bold/thin, text case: upper/title/mixed, typical word count)
7. Visual "brand signature" — is there a consistent element across all thumbnails? (Arrow, circle, specific color, logo, etc.)

Return ONLY this JSON:
{
  "thumbnail_dna": {
    "dominant_colors": ["<hex>", "<hex>", "<hex>"],
    "text_position": "<left|center|right|bottom|none|varied>",
    "face_presence_pct": <float 0-100>,
    "dominant_emotion": "<shock|excitement|concern|curiosity|neutral|none>",
    "background_type": "<solid|gradient|scene|blurred|stock>",
    "text_style": "<bold-caps|bold-title|thin-title|mixed>",
    "typical_word_count_in_thumbnail": <integer>,
    "brand_signature": "<description or 'none'>",
    "visual_complexity": "<minimal|moderate|busy>"
  },
  "thumbnail_consistency_score": <integer 0-100>,
  "thumbnail_visual_summary": "<2-3 sentence description>"
}`;

let thumbnailDNA = null;
let pass2Ok = false;
if (thumbs.length > 0) {
  const visionContent = thumbs.map(url => ({ type: 'image', source: { type: 'url', url } }));
  visionContent.push({ type: 'text', text: pass2TextPrompt });
  const pass2 = await callClaude([{ role: 'user', content: visionContent }], 1500, 4, 'pass2_thumbnails');
  pass2Ok = pass2.ok;
  if (pass2.ok) thumbnailDNA = parseJson(pass2.text);
}

// ─── Pass 3: Content Strategy ─────────────────────────────────────────────
const contentLines = recentVideos.map(v => `- "${v.title}" → ${v.views} views | ${v.duration_minutes}min`).join('\n');
const uploadDates = recentVideos.map(v => v.published_at).filter(Boolean).slice(0, 20).join(', ');

const pass3Prompt = `CONTENT PILLAR + CADENCE ANALYSIS

Channel: ${channelName}

Video titles and view counts (last ${recentVideos.length}):
${contentLines}

Upload dates: ${uploadDates}
Subscriber count: ${data.subscriber_count || 'unknown'}

TASK:
1. Group these videos into 3-5 content pillars (recurring topic clusters)
2. Calculate upload cadence (frequency + preferred days)
3. Identify the relationship between video length and view performance
4. Summarize what makes this channel's content strategy distinctive

Return ONLY this JSON:
{
  "content_pillars": [
    {
      "pillar_name": "<topic cluster name>",
      "description": "<what this content covers>",
      "example_titles": ["<title>", "<title>"],
      "pct_of_uploads": <float>,
      "avg_views": <integer>
    }
  ],
  "upload_cadence": {
    "uploads_per_week": <float>,
    "preferred_days": ["<day>"],
    "avg_video_length_minutes": <float>,
    "length_performance_correlation": "<longer performs better|shorter performs better|no clear pattern>"
  },
  "content_strategy_summary": "<3-4 sentence description of what makes this channel's content approach distinctive and replicable>",
  "replication_difficulty": "<easy|medium|hard>",
  "replication_notes": "<what would be hardest to replicate and why>"
}`;

const pass3 = await callClaude([{ role: 'user', content: pass3Prompt }], 1500, 4, 'pass3_content');
const contentStrategy = pass3.ok ? parseJson(pass3.text) : null;

// ─── Synthesis ────────────────────────────────────────────────────────────
// Even if passes fail, assemble what we have (partial record).
const titleFormulas = (titleDNA?.title_formulas) || [];
const topFormulaIdx = typeof titleDNA?.top_performing_formula === 'number' ? titleDNA.top_performing_formula : null;
const topFormula = (topFormulaIdx != null && titleFormulas[topFormulaIdx]) || titleFormulas[0] || null;

const thumbSummary = thumbnailDNA?.thumbnail_visual_summary || 'Thumbnail analysis unavailable.';
const facePct = thumbnailDNA?.thumbnail_dna?.face_presence_pct || 0;
const face = facePct > 60 ? 'face-forward' : (facePct > 20 ? 'mixed-face' : 'faceless');

const uploadsPerWeek = contentStrategy?.upload_cadence?.uploads_per_week;
const topPillar = contentStrategy?.content_pillars?.[0]?.pillar_name;

let styleSummary;
if (titleDNA && thumbnailDNA && contentStrategy && topFormula) {
  styleSummary = `${channelName} is a ${face} channel with a ${(uploadsPerWeek || 0).toFixed(1)}x/week cadence. ` +
    (topPillar ? `Top-performing content cluster: "${topPillar}". ` : '') +
    `Dominant title formula: ${topFormula.pattern_name} (${(topFormula.frequency_pct || 0).toFixed(0)}% of uploads, ${(topFormula.avg_views_when_used || 0).toLocaleString()} avg views). ` +
    thumbSummary;
} else {
  const missing = [];
  if (!titleDNA) missing.push('pass1_titles');
  if (!thumbnailDNA && thumbs.length > 0) missing.push('pass2_thumbnails');
  if (!contentStrategy) missing.push('pass3_content');
  styleSummary = `Partial analysis for ${channelName} (failed passes: ${missing.join(', ') || 'none'}).`;
}

const analysisCostUsd = (pass1.ok ? 0.06 : 0) + (pass2Ok ? 0.06 : 0) + (pass3.ok ? 0.03 : 0);

return [{
  json: {
    ...data,
    title_dna: titleDNA,
    thumbnail_dna_result: thumbnailDNA,
    content_strategy: contentStrategy,
    style_summary: styleSummary,
    analysis_cost_usd: Math.round(analysisCostUsd * 1000) / 1000,
    analysis_duration_ms: Date.now() - analysisStart,
    pass_status: {
      pass1_titles: pass1.ok,
      pass2_thumbnails: pass2Ok,
      pass3_content: pass3.ok
    }
  }
}];

// UPSERT style_profiles on (project_id, channel_id). Because style_profiles has
// no explicit unique constraint on (project_id, channel_id), we emulate upsert via
// read-or-insert: if a matching row exists, PATCH it; otherwise INSERT.
// Also: optional apply_to_project marker, alert creation, production_logs entry,
// and build the webhook response payload.

const data = $input.first().json;

// Short-circuit pass-throughs from earlier nodes
if (data.success === false) {
  return [{ json: data }];
}
if (data.skipped) {
  return [{ json: data }];
}

const projectId = data.project_id || null;
const channelId = data.channel_id;
const channelName = data.channel_name || '';
const applyToProject = data.apply_to_project === true;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const titleDNA = data.title_dna || {};
const thumbDNA = data.thumbnail_dna_result || {};
const content = data.content_strategy || {};

// Find linked competitor_channels row (if this channel is tracked under this project)
let competitorChannelId = null;
if (projectId) {
  try {
    const ccUrl = `${supabaseUrl}/rest/v1/competitor_channels?project_id=eq.${projectId}&channel_id=eq.${encodeURIComponent(channelId)}&select=id&limit=1`;
    const ccRes = await fetch(ccUrl, { method: 'GET', headers: sbHeaders });
    if (ccRes.ok) {
      const arr = await ccRes.json();
      if (Array.isArray(arr) && arr.length > 0) competitorChannelId = arr[0].id;
    }
  } catch (_) { }
}

const row = {
  project_id: projectId,
  competitor_channel_id: competitorChannelId,
  channel_id: channelId,
  channel_url: data.channel_url || null,
  channel_name: channelName,
  title_formulas: titleDNA.title_formulas || [],
  title_stats: titleDNA.title_stats || {},
  top_performing_formula_idx: typeof titleDNA.top_performing_formula === 'number' ? titleDNA.top_performing_formula : null,
  title_pattern_summary: titleDNA.title_pattern_summary || null,
  thumbnail_dna: thumbDNA.thumbnail_dna || {},
  thumbnail_consistency_score: typeof thumbDNA.thumbnail_consistency_score === 'number' ? thumbDNA.thumbnail_consistency_score : null,
  thumbnail_visual_summary: thumbDNA.thumbnail_visual_summary || null,
  content_pillars: content.content_pillars || [],
  upload_cadence: content.upload_cadence || {},
  content_strategy_summary: content.content_strategy_summary || null,
  replication_difficulty: ['easy','medium','hard'].includes(content.replication_difficulty) ? content.replication_difficulty : null,
  replication_notes: content.replication_notes || null,
  style_summary: data.style_summary || null,
  videos_analyzed: data.videos_count || 0,
  thumbnails_analyzed: data.thumbnails_count || 0,
  applied_to_project: applyToProject && !!projectId,
  applied_at: (applyToProject && projectId) ? new Date().toISOString() : null,
  analysis_cost_usd: data.analysis_cost_usd || 0,
  analyzed_at: new Date().toISOString()
};

// Emulated UPSERT: look up existing row, PATCH if found, INSERT otherwise.
let styleProfile = null;
let existingId = null;
if (!data.force) {
  // Only skip re-writing on dedupe key match; but force=true here means the resolver
  // already let us through, so we still want to overwrite the most recent row.
}

try {
  let lookupUrl = `${supabaseUrl}/rest/v1/style_profiles?channel_id=eq.${encodeURIComponent(channelId)}&order=analyzed_at.desc&limit=1&select=id`;
  if (projectId) {
    lookupUrl += `&project_id=eq.${projectId}`;
  } else {
    lookupUrl += `&project_id=is.null`;
  }
  const lookupRes = await fetch(lookupUrl, { method: 'GET', headers: sbHeaders });
  if (lookupRes.ok) {
    const arr = await lookupRes.json();
    if (Array.isArray(arr) && arr.length > 0) existingId = arr[0].id;
  }
} catch (_) { }

let persistError = null;
try {
  if (existingId) {
    const patchRes = await fetch(`${supabaseUrl}/rest/v1/style_profiles?id=eq.${existingId}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=representation' },
      body: JSON.stringify(row)
    });
    if (patchRes.ok) {
      const arr = await patchRes.json();
      styleProfile = Array.isArray(arr) && arr[0] ? arr[0] : null;
    } else {
      persistError = `PATCH failed: HTTP ${patchRes.status}: ${(await patchRes.text()).slice(0, 200)}`;
    }
  } else {
    const insRes = await fetch(`${supabaseUrl}/rest/v1/style_profiles`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=representation' },
      body: JSON.stringify(row)
    });
    if (insRes.ok) {
      const arr = await insRes.json();
      styleProfile = Array.isArray(arr) && arr[0] ? arr[0] : null;
    } else {
      persistError = `INSERT failed: HTTP ${insRes.status}: ${(await insRes.text()).slice(0, 200)}`;
    }
  }
} catch (e) {
  persistError = e.message;
}

// Create dashboard alert (requires project_id)
if (projectId && styleProfile?.id) {
  try {
    await fetch(`${supabaseUrl}/rest/v1/competitor_alerts`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        competitor_channel_id: competitorChannelId,
        alert_type: 'style_dna_ready',
        severity: 'normal',
        title: `🧬 Style DNA ready: ${channelName}`.slice(0, 200),
        message: (data.style_summary || 'Style profile analysis complete.').slice(0, 2000),
        metadata: {
          style_profile_id: styleProfile.id,
          channel_id: channelId,
          channel_name: channelName,
          videos_analyzed: row.videos_analyzed,
          thumbnails_analyzed: row.thumbnails_analyzed,
          pass_status: data.pass_status || {}
        }
      })
    });
  } catch (_) { }
}

// TODO (Sprint S3/S6): if applyToProject, inject style DNA into prompt_configs for
// topic generation + thumbnail prompts. For S2, applied_to_project + applied_at
// are written above as a marker; actual injection is out of scope.

// production_logs
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: null,
      stage: 'style_dna',
      scene_number: null,
      action: '3pass_analysis',
      status: persistError ? 'partial' : 'success',
      duration_ms: data.analysis_duration_ms || null,
      cost_usd: data.analysis_cost_usd || 0,
      retry_count: 0
    })
  });
} catch (_) { }

return [{
  json: {
    success: !persistError,
    skipped: false,
    style_profile: styleProfile,
    style_profile_id: styleProfile?.id || null,
    channel_id: channelId,
    channel_name: channelName,
    project_id: projectId,
    videos_analyzed: row.videos_analyzed,
    thumbnails_analyzed: row.thumbnails_analyzed,
    pass_status: data.pass_status || {},
    applied_to_project: row.applied_to_project,
    analysis_cost_usd: data.analysis_cost_usd || 0,
    persist_error: persistError,
    via_webhook: data.via_webhook
  }
}];
